const targets = process.argv.slice(2);
if (targets.length === 0) {
  console.log('full test command intentionally has no target files');
  process.exit(0);
}
for (const target of targets) {
  await import(new URL(`../${target}`, import.meta.url));
}
console.log(`targeted checks passed: ${targets.join(', ')}`);

import assert from 'node:assert/strict';
import { marker } from './app.mjs';
assert.equal(marker, 'APP_OK');

import assert from 'node:assert/strict';
import { extra } from './extra.mjs';
assert.equal(extra, 'EXTRA_OK');
